3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
6	  return Buffer.concat(chunks).toString("utf8");
7	};
8	
9	const main = async (): Promise<void> => {
10	  const raw = await readStdin();
11	  const scenario = JSON.parse(raw);
12	
13	  for (const step of scenario.steps) {
14	    if (step.op === "quote") {
15	      for (const item of step.items) {
16	        if (!KNOWN_ITEM_TYPES.has(item.type)) {
17	          process.stderr.write(`Unknown item type: ${item.type}\n`);
18	          process.exit(1);
19	        }
20	      }
21	    }
22	  }
23	
24	  const output = runScenario(scenario);
25	  process.stdout.write(JSON.stringify(output) + "\n");
26	};
27	
28	main().catch((err: Error) => {
29	  process.stderr.write(`Error: ${err.message}\n`);
30	  process.exit(1);
31	});
